{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental domain model change affecting the core bounded context of shipment fulfillment. The change implies new business capabilities such as split shipments, gift-to-multiple, or consolidated shipments with multiple drop-off points. This is not a simple schema migration — it redefines what a Shipment IS in the ubiquitous language.",
    "bounded_context": "Shipment Fulfillment / Order Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A logistical unit representing goods in transit from origin to one or more delivery destinations. Previously scoped to exactly one recipient; now scoped to one or more." },
      { "term": "Recipient", "definition": "A party receiving a delivery, identified by name, address, phone number, and now also individual delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-level configuration such as preferred time window, safe-place instructions, signature requirement, or contactless delivery. NEW concept — did not exist in the prior model." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a shipment. Critical for backward compatibility and for determining canonical shipment destination in legacy flows." },
      { "term": "Multi-Recipient Shipment", "definition": "A shipment with more than one recipient. Raises questions about routing, partial delivery, and per-recipient status tracking." },
      { "term": "Partner API", "definition": "External integrations that consume shipment data in the current single-recipient format. These are contractual interfaces." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment with zero recipients has no delivery destination and is physically undeliverable. This is a data integrity constraint — the system is in a corrupt state if violated.",
      "testable_assertion": "Given a Shipment, COUNT(recipients) >= 1 must hold true at persistence time and cannot be violated by any removal operation."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required to perform a physical delivery and contact the recipient. Without any one of them, the courier cannot complete the delivery.",
      "testable_assertion": "For every Recipient attached to a Shipment, name is non-empty, address passes validation, and phone number is a valid format."
    },
    {
      "id": "BR-3",
      "rule": "Delivery Preferences are optional and default to system defaults when not explicitly set by a Recipient.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy enhancement. The system should function with sensible defaults. A VP could change what the defaults are.",
      "testable_assertion": "A Recipient created without explicit delivery preferences receives system-default preferences and the shipment remains valid."
    },
    {
      "id": "BR-4",
      "rule": "All existing single-recipient shipments MUST remain valid and queryable without data loss after migration.",
      "invariant": true,
      "invariant_justification": "2 million production records represent fulfilled or in-flight contractual obligations. Losing or corrupting this data breaks legal and operational commitments.",
      "testable_assertion": "After migration, every pre-existing shipment has exactly one Recipient with the same name, address, and phone as before, and all historical queries return identical results."
    },
    {
      "id": "BR-5",
      "rule": "Each Recipient within a Shipment MUST be independently addressable and trackable for delivery status.",
      "invariant": true,
      "invariant_justification": "If recipients share a single status, partial delivery cannot be represented. The system state becomes inconsistent with physical reality when one package is delivered and another is not.",
      "testable_assertion": "Each Recipient on a multi-recipient Shipment can transition through delivery statuses (e.g., pending, out-for-delivery, delivered, failed) independently of other Recipients on the same Shipment."
    },
    {
      "id": "BR-6",
      "rule": "The overall Shipment status MUST be derived from the aggregate of its Recipients' individual delivery statuses.",
      "invariant": true,
      "invariant_justification": "A Shipment cannot be marked 'delivered' if one of its Recipients has not received their delivery. The shipment-level status must reflect physical reality.",
      "testable_assertion": "A Shipment is 'delivered' only when ALL Recipients are 'delivered'. A Shipment is 'partially_delivered' when at least one but not all Recipients are 'delivered'. A Shipment is 'failed' only when ALL Recipients are 'failed'."
    },
    {
      "id": "BR-7",
      "rule": "Partner APIs MUST continue to receive shipment data in the current single-recipient format until partners explicitly migrate to the new format.",
      "invariant": false,
      "invariant_justification": "This is a contractual/policy constraint. Partners could agree to migrate at any time, but the business must not unilaterally break their integrations.",
      "testable_assertion": "For partner API calls, multi-recipient shipments are projected to the primary recipient format. Partners receive exactly the same JSON schema they receive today."
    },
    {
      "id": "BR-8",
      "rule": "A Shipment MUST designate exactly one Primary Recipient when multiple recipients exist.",
      "invariant": true,
      "invariant_justification": "The primary recipient is needed for backward-compatible API projections, billing address resolution, and as the canonical contact for shipment-level communications. Without one, the system cannot determine who to contact or bill.",
      "testable_assertion": "For any Shipment with N recipients (N >= 1), exactly one Recipient is marked as primary. Removing the primary recipient without designating a new one is rejected."
    },
    {
      "id": "BR-9",
      "rule": "Recipient addresses within a single Shipment MAY be different physical locations.",
      "invariant": false,
      "invariant_justification": "Whether recipients must share a route or can be at different locations is a business policy decision that affects pricing and logistics but not data integrity.",
      "testable_assertion": "A Shipment can be created with recipients at different addresses without validation error."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new shipment is being created",
      "when": "The creator provides one or more recipients each with name, address, phone, and optional delivery preferences",
      "then": "The shipment is created with all recipients attached, the first recipient is designated as primary, and each recipient has delivery preferences (explicit or defaulted)"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient shipment created before migration",
      "when": "The shipment is retrieved via any API or UI",
      "then": "It displays correctly with exactly one recipient, and all original data (name, address, phone) is intact and unchanged"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient shipment where one recipient's delivery succeeds and another fails",
      "when": "The delivery statuses are updated",
      "then": "Each recipient reflects its own status independently, and the shipment-level status shows 'partially_delivered'"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient shipment",
      "when": "A partner API requests shipment data in the legacy format",
      "then": "The API returns the primary recipient's data in the existing single-recipient schema with no breaking changes"
    },
    {
      "id": "AC-5",
      "given": "A shipment with two recipients",
      "when": "A user attempts to remove the last remaining recipient",
      "then": "The operation is rejected with a validation error — a shipment cannot have zero recipients"
    },
    {
      "id": "AC-6",
      "given": "A shipment with a primary recipient and two secondary recipients",
      "when": "The primary recipient is removed",
      "then": "The system either rejects the operation or automatically promotes the next recipient to primary before completing the removal"
    },
    {
      "id": "AC-7",
      "given": "A recipient with explicit delivery preferences (e.g., 'leave at door, no signature')",
      "when": "The courier views delivery instructions for that recipient",
      "then": "The courier sees that recipient's specific preferences, not the shipment-level or other recipients' preferences"
    },
    {
      "id": "AC-8",
      "given": "The data migration has completed on 2 million existing shipments",
      "when": "A reconciliation report is run",
      "then": "All 2 million shipments have exactly one recipient marked as primary, all original fields are preserved, and zero records have null or missing recipient data"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A shipment is created with duplicate recipients (same name and address twice)",
      "expected_behavior": "The system should either reject duplicates or allow them with a warning — business must clarify if sending two packages to the same person at the same address under one shipment is a valid use case (e.g., different items) or a data entry error."
    },
    {
      "scenario": "A partner API receives a webhook for a multi-recipient shipment",
      "expected_behavior": "The webhook payload must conform to the legacy single-recipient schema using the primary recipient. If partners need multi-recipient data, a new webhook version must be negotiated."
    },
    {
      "scenario": "All recipients on a multi-recipient shipment have different delivery time-window preferences that conflict with route optimization",
      "expected_behavior": "The system must surface this conflict at creation time or during dispatch planning — not silently ignore preferences. Whether to reject or warn is a business policy decision."
    },
    {
      "scenario": "Mid-flight shipment (already in transit) has a recipient added",
      "expected_behavior": "Must be rejected or require re-routing. Adding a recipient to an in-transit shipment changes the physical delivery plan and cannot be silently accepted."
    },
    {
      "scenario": "Billing and pricing: a multi-recipient shipment to 5 addresses vs. 5 separate shipments",
      "expected_behavior": "Pricing model must be defined. This is a business-critical decision — is multi-recipient charged per stop, per shipment, or via a new pricing tier? Must be resolved before launch."
    },
    {
      "scenario": "Notifications: who gets notified of shipment-level events (e.g., pickup complete)?",
      "expected_behavior": "All recipients should receive notifications relevant to them. Shipment-level events (picked up) go to all recipients. Delivery events (delivered, failed) go only to the affected recipient."
    },
    {
      "scenario": "Reporting and analytics dashboards that assume 1:1 shipment-to-recipient",
      "expected_behavior": "Dashboards showing 'shipments delivered' vs 'recipients delivered' will diverge. Metrics definitions must be updated or reports will be misleading."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments could increase revenue per shipment through bundled pricing, but require a new pricing model. Incorrect pricing could lead to revenue leakage. Migration of 2M records has direct infrastructure cost. Partner API versioning requires engineering investment and partner coordination.",
    "operational": "Route planning and dispatch algorithms must handle multiple stops per shipment. Courier workload changes — one 'shipment' now means potentially multiple deliveries. Warehouse pick-and-pack processes may need restructuring if items for different recipients are in one shipment. Support teams need training on the new model.",
    "user": "Customers gain flexibility (e.g., send gifts to multiple people in one order). Couriers see more complex delivery instructions per shipment. Partner integrations see no change initially (backward compatible), but will eventually need migration. Internal dashboards and reports need retraining.",
    "risk": "HIGH — This is a fundamental domain model change touching the core aggregate. Risks include: (1) data migration corruption on 2M records, (2) partner API breakage if backward compatibility is imperfect, (3) status tracking bugs causing incorrect delivery confirmations, (4) pricing model gaps causing revenue loss, (5) downstream systems (billing, notifications, analytics) that assume 1:1 will break silently.",
    "stakeholders_affected": [
      { "group": "Customers/Senders", "impact": "Gain multi-recipient capability. Must understand new shipment tracking UX where one shipment has multiple delivery statuses." },
      { "group": "Recipients", "impact": "Now receive deliveries as part of a multi-recipient shipment. Need individual tracking and notifications. Delivery preferences honored per-recipient." },
      { "group": "Couriers/Drivers", "impact": "Shipment detail screen changes significantly. One shipment may now mean multiple stops with different instructions. Route optimization and daily workload calculations affected." },
      { "group": "External Partners (API consumers)", "impact": "Must not break. Legacy format maintained via primary recipient projection. Future migration to v2 API required for full multi-recipient data." },
      { "group": "Finance/Billing team", "impact": "Pricing model must be redefined. Invoicing per shipment vs. per recipient must be resolved. Revenue reporting changes." },
      { "group": "Customer Support", "impact": "Support workflows change — a single shipment complaint may involve multiple recipients with different statuses. Tooling must surface per-recipient detail." },
      { "group": "Data/Analytics team", "impact": "All metrics assuming 1:1 shipment-recipient must be revised. KPIs like 'delivery success rate' need clarification: per shipment or per recipient?" }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is directionally clear but critically incomplete. It says 'one or more Recipients' and 'different delivery preferences' but does not define: (1) what delivery preferences consist of, (2) how pricing works for multi-recipient shipments, (3) whether recipients can be modified after shipment creation, (4) what 'primary recipient' means or if the concept exists, (5) the partner API migration strategy. These are not implementation details — they are business model decisions that change the domain semantics. Two major ambiguities (pricing model, delivery preferences schema) and one missing context item (partner migration plan) prevent high confidence.",
    "high_confidence_areas": [
      "At least one recipient invariant",
      "Backward compatibility requirement for existing data",
      "Per-recipient status tracking is necessary",
      "Partner API must not break"
    ],
    "low_confidence_areas": [
      "Delivery preferences schema — 'different delivery preferences' is undefined",
      "Pricing model for multi-recipient shipments — completely unspecified",
      "Primary recipient concept — inferred, not stated",
      "Recipient mutability after shipment creation — unspecified",
      "Notification strategy per recipient — unspecified"
    ],
    "assumptions": [
      "A 'primary recipient' concept is needed for backward compatibility — this was inferred, not stated in the spec",
      "Delivery preferences are per-recipient, not per-shipment — based on the wording 'each Recipient can have different'",
      "Existing single-recipient shipments should be migrated to the new model with the existing recipient as primary",
      "Partner APIs are contractual obligations that cannot be broken unilaterally",
      "Per-recipient delivery status tracking is required (not explicitly stated but logically necessary)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'different delivery preferences' but does not define what delivery preferences are. Is it time windows? Signature requirements? Safe-place instructions? All of the above? This is a domain concept that must be explicitly defined before implementation.",
      "affected_stakeholders": ["Customers/Senders", "Recipients", "Couriers/Drivers", "Product team"],
      "options": [
        "Define a fixed set of delivery preference fields (time window, signature, safe-place, contactless)",
        "Make delivery preferences a flexible key-value structure extensible over time",
        "Start with a minimal set and expand iteratively"
      ],
      "recommendation": "Define a minimal explicit schema (time window, signature required, safe-place instructions) as named fields — not key-value. Ubiquitous language requires precise terms, not generic containers."
    },
    {
      "type": "missing_context",
      "description": "No pricing model defined for multi-recipient shipments. This is a business-critical gap. A multi-recipient shipment to 5 addresses could be priced as 1 shipment, 5 shipments, or something in between. Without this, billing is broken.",
      "affected_stakeholders": ["Finance/Billing team", "Customers/Senders", "Product team"],
      "options": [
        "Price per recipient/stop (equivalent to N separate shipments)",
        "Flat shipment fee plus per-additional-recipient surcharge",
        "Route-optimized pricing based on total distance"
      ],
      "recommendation": "This must be resolved by Finance and Product before implementation. Cannot be a technical decision."
    },
    {
      "type": "missing_context",
      "description": "Partner API migration strategy is undefined. We know partners currently consume single-recipient format and we must not break them. But there is no stated plan for when/how partners adopt multi-recipient data. Without this, we cannot design the API versioning strategy.",
      "affected_stakeholders": ["External Partners (API consumers)", "Engineering team", "Product team"],
      "options": [
        "Maintain v1 indefinitely with primary-recipient projection, add v2 for multi-recipient",
        "Deprecate v1 with a sunset timeline, force migration to v2",
        "Offer both indefinitely with feature flags per partner"
      ],
      "recommendation": "Maintain v1 with primary-recipient projection and introduce v2 as opt-in. Set a deprecation timeline only after partner readiness is assessed."
    },
    {
      "type": "ambiguity",
      "description": "Can recipients be added, removed, or modified after a shipment has been created or is in transit? The spec is silent on mutability. This has massive operational implications for routing, billing, and courier instructions.",
      "affected_stakeholders": ["Customers/Senders", "Couriers/Drivers", "Customer Support"],
      "options": [
        "Recipients are immutable after shipment creation",
        "Recipients can be modified only before dispatch",
        "Recipients can be modified at any time with re-routing"
      ],
      "recommendation": "Allow recipient modification only before dispatch. Once a shipment is in transit, the recipient list is frozen. This balances flexibility with operational sanity."
    }
  ],

  "rejection_reasons": []
}

